悬疑小说::/xuanyi/{{page}}.html
游戏小说::/youxi/{{page}}.html
奇幻小说::/qihuan/{{page}}.html
诸天无限::/zhutianwuxian/{{page}}.html
军事小说::/junshi/{{page}}.html
重生小说::/chongsheng/{{page}}.html
武侠小说::/wuxia/{{page}}.html
体育小说::/tiyu/{{page}}.html
言情小说::/yanqing/{{page}}.html`;

var categories = [];
var lines = inputData.split('\n').filter(l => l.trim());
var items = [];

for (var i = 0; i < lines.length; i++) {
    var parts = lines[i].split('::');
    var title = parts[0] || "";
    var url = (parts[1] || "").trim();

    if (!url) {
        categories.push({
            "title": title,
            "url": "",
            "style": {"layout_flexGrow":1,"layout_flexBasisPercent":1}
        });
    } else {
        items.push({
            "title": title,
            "url": url,
            "style": {"layout_flexGrow":1,"layout_flexBasisPercent":0.25}
        });
    }
}

for (var j = 0; j < items.length; j++) {
    categories.push(items[j]);
}

var remainder = items.length % 3;
if (remainder > 0) {
    for (var k = 0; k < 3 - remainder; k++) {
        categories.push({
            "title": "----------",
            "url": "",
            "style": {"layout_flexGrow":1,"layout_flexBasisPercent":0.25}
        });
    }
}

JSON.stringify(categories);

