ruleContent.content:
class.main-text.0@span@p@html
<js>

var fullHtml = String(java.getString('@css:.main-text@html', false) || '');

var aRegex = /<div class="text-center grayout warning-tag">[\s\S]*?<\/div>/; 
var aMatch = fullHtml.match(aRegex);
var aPart = '';
if (aMatch && aMatch[0]) {
    var aHtml = aMatch[0];
    var aText = aHtml.replace(/<[^>]+>/g, '').trim();
    if (aText && aText !== '' && !aText.includes('本帖非边限对外公开')) {
        aPart = '作者有话说：\n' + aHtml + '\n----------------\n';
    }
    fullHtml = fullHtml.replace(aRegex, ''); 
}

var bRegex = /<div class="text-left grayout">[\s\S]*?<\/div>/; 
var bMatch = fullHtml.match(bRegex);
var bPart = '';
if (bMatch && bMatch[0]) {
    var bHtml = bMatch[0];
    var bText = bHtml.replace(/<[^>]+>/g, '').trim();
    if (bText && bText !== '' && bHtml.includes('<p>') && !bHtml.includes('进入论坛模式')) {
        bPart = '\n----------------\n' + '作者有话说：\n' + bHtml;
    }
    fullHtml = fullHtml.replace(bRegex, ''); 
}

if (fullHtml.includes('<span class="hidden">')) {
    fullHtml = fullHtml.substring(0, fullHtml.indexOf('<span class="hidden">'));
}
if (fullHtml.includes('进入论坛模式')) {
    fullHtml = fullHtml.substring(0, fullHtml.indexOf('进入论坛模式'));
}

var publishTime = (java.getString('@css:.brief-0 p:nth-child(1)@text', false) || '').trim();
var editTime = (java.getString('@css:.brief-0 p:nth-child(2)@text', false) || '').trim();
var timeStr = '⌚️ 发布：' + publishTime;
if (editTime && editTime.includes('-')) timeStr += ' | 修改：' + editTime;

var subtitle = java.getString('@css:strong.h5@text', false) || '';
var titlePart = subtitle ? '【' + subtitle + '】\n' : ''; 
var timePart = timeStr ? timeStr + '\n\n' : '\n\n';
result = titlePart + timePart + aPart + fullHtml + bPart;
</js>

