function showCmt(url, sources, ydv) {
    let {
        java,
        cache
    } = this;
    const currentTime = Date.now();
    const click = cache.getFromMemory(url);
    let isqread = false;
    try {
        java.qread();
        isqread = true;
    } catch (e) {}
    if (click < 1 && !isqread && !ydv) {
        cache.putMemory(url, click + 1);
        return;
    } else {
        if (isqread) {
            java.startBrowserDp(url, sources + '段评');
        } else if (ydv) {
            let paradata = new Date().toLocaleDateString();
            let htmlContent = cache.get(paradata);
            if (!htmlContent || String(htmlContent).indexOf("评论") == -1) {
                java.longToast(`\n${paradata} 初始化段评页面,请稍等~`);
                try {
                    htmlContent = java.ajax(url);
                } catch {
                    htmlContent = paraHtml(url);
                }

                cache.put(paradata, htmlContent);
                java.longToast(`\n${paradata} 初始化段评页面成功~`);
            }
            java.showBrowser(
                url,
                htmlContent,
                `window.java=java;`,
                JSON.stringify({
                    "expandedCornersRadius": 20,
                    "dismissOnTouchOutside": true,
                    "isDraggable": true,
                    "shouldDimBackground": true,
                    "backgroundDimAmount": 0.5,
                    "hardwareAccelerated": true,
                    "isNestedScrollingEnabled": true,
                    "isGestureInsetBottomIgnored": true,
                    "setFitToContents": true,
                    "isHideable": true,
                    "heightPercentage": 0.8
                })
            );
        } else {
            java.startBrowser(url, sources + '段评');
        }
    }
}



