            "[爱慕]": "${baser_url}/static/emoji/emoji_dr_6.png",
            "[飞吻]": "${baser_url}/static/emoji/emoji_dr_7.png",
            "[奸笑]": "${baser_url}/static/emoji/emoji_dr_8.png",
            "[尬笑]": "${baser_url}/static/emoji/emoji_dr_9.png",
            "[思考]": "${baser_url}/static/emoji/emoji_dr_10.png",
            "[撇嘴]": "${baser_url}/static/emoji/emoji_dr_11.png",
            "[做鬼脸]": "${baser_url}/static/emoji/emoji_dr_12.png",
            "[酷]": "${baser_url}/static/emoji/emoji_dr_13.png",
            "[翻白眼]": "${baser_url}/static/emoji/emoji_dr_14.png",
            "[惊呆]": "${baser_url}/static/emoji/emoji_dr_15.png",
            "[震惊]": "${baser_url}/static/emoji/emoji_dr_16.png",
            "[送心]": "${baser_url}/static/emoji/emoji_dr_17.png",
            "[委屈]": "${baser_url}/static/emoji/emoji_dr_18.png",
            "[快哭了]": "${baser_url}/static/emoji/emoji_dr_19.png",
            "[笑哭]": "${baser_url}/static/emoji/emoji_dr_20.png",
            "[哭]": "${baser_url}/static/emoji/emoji_dr_21.png",
            "[大笑]": "${baser_url}/static/emoji/emoji_dr_22.png",
            "[舔屏]": "${baser_url}/static/emoji/emoji_dr_23.png",
            "[怒]": "${baser_url}/static/emoji/emoji_dr_24.png",
            "[捂脸]": "${baser_url}/static/emoji/emoji_dr_25.png",
