function showChapterComments() {
    var java = this.java,
        chapter = this.chapter,
        cookie = this.cookie;
    var aid = (String(chapter.url).match(/aid\W+(\d+)/) || [])[1] || "";
    var key = "";
    try {
        if (cookie && cookie.getKey) {
            var v = cookie.getKey("https://api.lightnovel.fun", "lkcfg");
            if (v) {
                var cc = JSON.parse(decodeURIComponent(v));
                if (cc.key) key = cc.key;
            }
        }
    } catch (e) {}
    if (!key) {
        try {
            key = "" + (java.get("lk_key") || "");
        } catch (e) {}
    }
    var paramsHtml = '<div class="hidden" id="params">\'' + aid + '@@' + key + '\'</div>';
    java.showBrowser("", reviewHtmlTemplate.replace("$2", paramsHtml), "window.run=run", '{"heightPercentage":0.8,"expandedCornersRadius":20,"hideFriction":0.9}');
}

function escapeHtml(str) {
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function fixRelativeUrls(html, origin) {
    if (html == null) return '';
    html = String(html);
    if (!html || !origin) return html;
    return html.replace(/\bsrc="([^"]+)"/g, function(m, url) {
        if (/^https?:\/\//i.test(url) || /^data:/i.test(url)) return m;
        if (url.charAt(0) === '/') return 'src="' + origin + url + '"';
        return 'src="' + origin + '/' + url + '"';
    });
}

function unescapeLkTags(s) {
    s = s.replace(/&lt;br\s*\/?&gt;/gi, "<br>");
    s = s.replace(/&lt;img\s+src=&quot;([^&]+)&quot;[\s\S]*?&gt;/gi, '<img src="$1" style="height:1.4em;vertical-align:middle">');
    return s;
}

function getChapterComments(param) {
    var java = this.java;
    var parts = ("" + param).split("@@");
    var aid = parts[0] || "";
    var key = parts[1] || "";
    if (!key) {
        try {
            key = "" + (java.get("lk_key") || "");
        } catch (e) {}
    }
    var body = JSON.stringify({
        platform: "android",
        client: "app",
        sign: "",
        ver_name: "0.11.53",
        ver_code: 193,
        gz: 0,
        d: {
            aid: parseInt(aid),
            page: 1,
            page_size: 20,
            security_key: key
        }
    });
    var resp = String(java.post("https://api.lightnovel.fun/api/discuss/get-topic", body, {
        "Content-Type": "application/json"
    }).body());
    var r = JSON.parse(resp);
    var lst = (r.data && r.data.list) || [];
    if (!lst.length) return "";
    var result = [];
    for (var i = 0; i < lst.length; i++) {
        var c = lst[i];
        var u = c.user_info || {};
        var item = '<li class="comment-item">';
        item += '<div class="comment-header"><span class="comment-author">' + escapeHtml(u.nickname || "匿名") + '</span><span class="comment-meta">' + escapeHtml(c.time || "") + '</span></div>';
        item += '<div class="comment-text">' + unescapeLkTags(escapeHtml(c.content || "")) + '</div>';
        var rl = c.reply_list || [];
        for (var k = 0; k < rl.length; k++) {
            var rc = rl[k];
            var ru = rc.user_info || {};
            item += '<div class="comment-quote"><b>' + escapeHtml(ru.nickname || "") + '</b>: ' + unescapeLkTags(escapeHtml(rc.content || "")) + '</div>';
        }
        item += '</li>';
        result.push(item);
    }
    return result.join("");
}

function postForumReply(chapterUrl, content, replyData) {
    var tokenBody;
    try {
        tokenBody = this.java.post(
            chapterUrl,
            'plxf=getAuthToken', {
                'Content-Type': 'application/x-www-form-urlencoded'
            }
        ).body();
    } catch (e) {
        return JSON.stringify({
            status: 500,
            msg: '無法連接伺服器'
        });
    }
    var tokenMatch = /<JinJing>(.*?)<\/JinJing>/.exec(tokenBody);
    if (!tokenMatch) {
        return JSON.stringify({
            status: 500,
            msg: '獲取令牌失敗'
        });
    }
    var token = tokenMatch[1];
    var originMatch = /^(https?:\/\/[^\/]+)/.exec(chapterUrl);
    var origin = originMatch ? originMatch[1] : source.bookSourceUrl;
    var forumMatch = /\/(\d+)\.html/.exec(chapterUrl);
    if (!forumMatch) {
        return JSON.stringify({
            status: 500,
            msg: '無法解析章節ID'
        });
    }
    var forumId = forumMatch[1];
    var postBody = 'data=forum&forum_id=' + encodeURIComponent(forumId) + '&content=' + encodeURIComponent(content);
    if (replyData) {
        postBody += '&reply=' + encodeURIComponent(replyData);
    }
    var responseBody;
    try {
        responseBody = this.java.post(
            origin + '/inc/forum_reply.php',
            postBody, {
                'Content-Type': 'application/x-www-form-urlencoded',
                'Authorization': token
            }
        ).body();
    } catch (e) {
        return JSON.stringify({
            status: 500,
            msg: '網路錯誤'
        });
    }
    return responseBody;
}

