function encSearchKey(keyword) {
    var keyStr = 'lzxHpH8PLGXcrCIQ';
    var keyBytes = new Packages.java.lang.String(keyStr).getBytes('UTF-8');
    var keyPadded = Packages.java.util.Arrays.copyOf(keyBytes, 32);
    var ivBytes = new Packages.java.lang.String(keyStr).getBytes('UTF-8');
    var ivPadded = Packages.java.util.Arrays.copyOf(ivBytes, 16);
    var Cipher = Packages.javax.crypto.Cipher;
    var SecretKeySpec = Packages.javax.crypto.spec.SecretKeySpec;
    var IvParameterSpec = Packages.javax.crypto.spec.IvParameterSpec;
    var secretKey = new SecretKeySpec(keyPadded, 'AES');
    var ivSpec = new IvParameterSpec(ivPadded);
    var cipher = Cipher.getInstance('AES/CBC/PKCS5Padding');
    cipher.init(Cipher.ENCRYPT_MODE, secretKey, ivSpec);
    var encrypted = cipher.doFinal(new Packages.java.lang.String(keyword).getBytes('UTF-8'));
    return String(Packages.android.util.Base64.encodeToString(encrypted, 2));
}

function decSearchUrl(encStr, numStr) {
    var ua = 'Mozilla/5.0 (Linux; Android 12; Pixel 6) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Mobile Safari/537.36';
    var keyStr = String(java.md5Encode(ua.toLowerCase() + numStr)).toLowerCase();
    var keyBytes = new Packages.java.lang.String(keyStr).getBytes('UTF-8');
    var Base64 = Packages.android.util.Base64;
    var allBytes = Base64.decode(encStr, 0);
    var iv = Packages.java.util.Arrays.copyOfRange(allBytes, 0, 16);
    var ct = Packages.java.util.Arrays.copyOfRange(allBytes, 16, allBytes.length);
    var Cipher = Packages.javax.crypto.Cipher;
    var SecretKeySpec = Packages.javax.crypto.spec.SecretKeySpec;
    var IvParameterSpec = Packages.javax.crypto.spec.IvParameterSpec;
    var secretKey = new SecretKeySpec(keyBytes, 'AES');
    var ivSpec = new IvParameterSpec(iv);
    var cipher = Cipher.getInstance('AES/CBC/PKCS5Padding');
    cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
    var decrypted = cipher.doFinal(ct);
    return String(new Packages.java.lang.String(decrypted, 'UTF-8'));
}

