function putUrl(n){
	const {java,source} = this;
	let urlData = {index:(n?n:0)};
 let data = [];
 urlsData.forEach((x,i)=>{
		    data.push({
		    	     t:x.replace(/https?:\/\//,''),
		    	     u:x
		    	})
    });
    urlData.data = data;
    source.putVariable(JSON.stringify(urlData));    
}

function getUrl(){
    const {source} = this;
    	let s = String(source.getVariable());
    if(!s){
    	     this.putUrl();
        	 s = String(source.getVariable());
    	}
    let urlData = JSON.parse(s);
    let index = urlData.index;
    let data = urlData.data;
	return data[index].t.replace(/\/$/,'');	
}

